solution_code:
#include <iostream>

int sharedValue { 0 };

void addOne();

void addOne()
{
    ++sharedValue;
}

int main()
{
    std::cout << "Before: " << sharedValue << '\n';
    addOne();
    addOne();
    addOne();
    std::cout << "After: " << sharedValue << '\n';
    return 0;
}

