solution_code:
#include <iostream>

int counter { 0 };        // definition

void bump();              // forward declaration for bump

void bump()
{
    ++counter;
}

int main()
{
    extern int counter;   // forward declaration — refers to global counter
    bump();
    bump();
    bump();
    std::cout << "Count: " << counter << '\n';
    return 0;
}
